#include <stdio.h>
#include <time.h>
#include <string.h>

void log_error(const char *error_msg) {
    FILE *logfile = fopen("error_log.txt", "a");
    if (!logfile) {
        return;
    }

    time_t now = time(NULL);
    char *timestamp = ctime(&now);
    if (timestamp) {
        timestamp[strcspn(timestamp, "\n")] = 0;
    }

    fprintf(logfile, "[%s] ", timestamp ? timestamp : "Unknown time");
    fprintf(logfile, error_msg);
    fprintf(logfile, "\n");

    fclose(logfile);
}